parameters.jsonBody:
={
    "start": "{{ $fromAI('start', '', 'string') }}",
    "eventTypeId": {{ $json.cal_event_type_slots }},
    "attendee": {
      "name": "{{ $fromAI('name', '', 'string') }}",
      "email": "{{ $fromAI('email', '', 'string') }}",
      "timeZone": "{{ $json.cal_timezone }}",
      "language": "en",
      "phoneNumber": "{{ (() => { const raw = $fromAI('phone', 'Irish phone number. Return only the phone number.', 'string') || ''; let p = raw.replace(/[^0-9+]/g, ''); if (p.startsWith('00353')) p = '+353' + p.slice(5); if (p.startsWith('353')) p = '+353' + p.slice(3); if (p.startsWith('0')) p = '+353' + p.slice(1); if (!p.startsWith('+353')) p = '+353' + p; return p; })() }}"
    },
    "metadata": {
      "origem": "Instagram",
      "idLead": "{{ $fromAI('email', '', 'string') }}"
    }
  }
